import hashlib

class Block:
 def __init__(self, data, previous_hash):
 self.data = data
 self.hash_value = self._hash(data)
 self.previous_hash = previous_hash

 def _hash(self, data):
 return hashlib.sha256(data.encode()).hexdigest()

class Blockchain:
 def __init__(self):
 self.chain = [self._create_genesis_block()]

 def _create_genesis_block(self):
 return Block('Genesis Block', '0')

 def add_block(self, data):
 previous_hash = self.chain[-1].hash_value
 new_block = Block(data, previous_hash)
 self.chain.append(new_block)

# Example usage
blockchain = Blockchain()
blockchain.add_block('Transaction 1')
blockchain.add_block('Transaction 2')

#include <stdio.h>
#include <string.h>
#include <openssl/sha.h>

typedef struct Block {
 char data[256];
 unsigned char hash[SHA256_DIGEST_LENGTH];
 unsigned char previous_hash[SHA256_DIGEST_LENGTH];
} Block;

typedef struct Blockchain {
 Block* chain;
 int length;
} Blockchain;

void hash_data(const char* data, unsigned char* hash) {
 SHA256_CTX sha256;
 SHA256_Init(&sha256);
 SHA256_Update(&sha256, data, strlen(data));
 SHA256_Final(hash, &sha256);
}

void add_block(Blockchain* blockchain, const char* data) {
 Block new_block;
 strcpy(new_block.data, data);
 hash_data(data, new_block.hash);
 memcpy(new_block.previous_hash, blockchain->chain[blockchain->length - 1].hash, SHA256_DIGEST_LENGTH);
 blockchain->chain[blockchain->length++] = new_block;
}

int main() {
 Blockchain blockchain;
 blockchain.chain = malloc(sizeof(Block) * 10);
 blockchain.length = 0;
 add_block(&blockchain, 'Transaction 1');
 add_block(&blockchain, 'Transaction 2');
 return 0;
}
